#include <iostream>

class IntStack {
    static const int MAX_SIZE = 8;
    int m_data[MAX_SIZE];
    int m_count;
public:
    IntStack() : m_count{0} {}

    IntStack& operator+=(int value) {
        if (m_count < MAX_SIZE)
            m_data[m_count++] = value;
        return *this;
    }

    friend std::ostream& operator<<(std::ostream& out, const IntStack& s);
};

std::ostream& operator<<(std::ostream& out, const IntStack& s) {
    out << '[';
    for (int i = 0; i < s.m_count; ++i) {
        if (i > 0) out << ", ";
        out << s.m_data[i];
    }
    out << ']';
    return out;
}

int main() {
    int n;
    std::cin >> n;
    IntStack s;
    for (int i = 0; i < n; ++i) {
        int v;
        std::cin >> v;
        s += v;
    }
    std::cout << s << '\n';
    return 0;
}

