#include <iostream>

class IntStack {
    static const int MAX_SIZE = 8;
    int m_data[MAX_SIZE];
    int m_count;
public:
    IntStack() : m_count{0} {}

    IntStack(const IntStack& src) : m_count{src.m_count} {
        for (int i = 0; i < m_count; ++i)
            m_data[i] = src.m_data[i];
    }

    IntStack& operator+=(int value) {
        if (m_count < MAX_SIZE)
            m_data[m_count++] = value;
        return *this;
    }

    IntStack& operator--() {
        if (m_count > 0)
            --m_count;
        return *this;
    }

    explicit operator bool() const {
        return m_count > 0;
    }

    friend std::ostream& operator<<(std::ostream& out, const IntStack& s);
};

std::ostream& operator<<(std::ostream& out, const IntStack& s) {
    out << '[';
    for (int i = 0; i < s.m_count; ++i) {
        if (i > 0) out << ", ";
        out << s.m_data[i];
    }
    out << ']';
    return out;
}

int main() {
    int n;
    std::cin >> n;
    IntStack original;
    for (int i = 0; i < n; ++i) {
        int v; std::cin >> v;
        original += v;
    }
    int m;
    std::cin >> m;
    IntStack copy{original};
    for (int i = 0; i < m; ++i) --copy;
    std::cout << "original: "       << original << '\n';
    std::cout << "copy_after_pops: " << copy     << '\n';
    std::cout << "copy_empty: "      << (copy ? 0 : 1) << '\n';
    return 0;
}
